                    best_resulting_kvpr = resulting_kvpr
                    best_gpu = g
            if best_gpu is None:
                raise ValueError("Cannot place model")
            best_placement[best_gpu].append(model)

    # Local search: try moves and swaps to reduce max KVPR
    import random
    random.seed(42)

    def try_improve(placement):
        improved = True
        iterations = 0
        while improved and iterations < 200:
            improved = False
            iterations += 1
            current_max = max_kvpr(placement)

            # Try moving a model from the most loaded GPU to another
            worst_gpu = max(range(gpu_num), key=lambda g: kvpr_of_gpu(placement[g]))
            for model in list(placement[worst_gpu]):
