                    placement[worst_gpu].remove(model)
                    placement[target_g].append(model)
                    new_max = max_kvpr(placement)
                    if new_max < current_max - 1e-15:
                        improved = True
                        current_max = new_max
                        break
                    else:
                        placement[target_g].remove(model)
                        placement[worst_gpu].append(model)
                if improved:
                    break

            if not improved:
                # Try swaps between worst GPU and others
                for model_a in list(placement[worst_gpu]):
