                            if total_size_of(placement[other_g]) + size_diff_a >= GPU_MEM_SIZE:
                                continue
                            if total_size_of(placement[worst_gpu]) - size_diff_a >= GPU_MEM_SIZE:
                                continue
                            # Try swap
                            placement[worst_gpu].remove(model_a)
                            placement[other_g].remove(model_b)
                            placement[worst_gpu].append(model_b)
                            placement[other_g].append(model_a)
                            new_max = max_kvpr(placement)
                            if new_max < current_max - 1e-15:
                                improved = True
                                current_max = new_max
                                break
                            else:
                                placement[other_g].remove(model_a)
                                placement[worst_gpu].remove(model_b)
                                placement[worst_gpu].append(model_a)
                                placement[other_g].append(model_b)
                        if improved:
                            break
                    if improved:
                        break
        return placement

    best_placement = try_improve(best_placement)

    # Also try a second initial placement: greedy by resulting KVPR
    sorted_models2 = sorted(model_list, key=lambda m: m.model_size, reverse=True)
    alt_placement = {g: [] for g in range(gpu_num)}
    for model in sorted_models2:
        best_gpu = None
        best_resulting_kvpr = float('inf')
        for g in range(gpu_num):
            new_size = total_size_of(alt_placement[g]) + model.model_size
            if new_size >= GPU_MEM_SIZE:
                continue
            new_rate = sum(m.req_rate / m.slo for m in alt_placement[g]) + model.req_rate / model.slo
            resulting_kvpr = new_rate / (GPU_MEM_SIZE - new_size)
            if resulting_kvpr < best_resulting_kvpr:
                best_resulting_kvpr = resulting_kvpr
                best_gpu = g
        if best_gpu is None:
            break
        alt_placement[best_gpu].append(model)
    else:
        alt_placement = try_improve(alt_placement)
        if max_kvpr(alt_placement) < max_kvpr(best_placement):
            best_placement = alt_placement

    return best_placement

